import WidgetKit
import SwiftUI
import AppIntents

struct StepEntry: TimelineEntry {
    let date: Date
    let steps: Int
}

struct StepProvider: TimelineProvider {
    func placeholder(in context: Context) -> StepEntry {
        StepEntry(date: Date(), steps: 0)
    }
    func getSnapshot(in context: Context, completion: @escaping (StepEntry) -> ()) {
        completion(StepEntry(date: Date(), steps: 0))
    }
    func getTimeline(in context: Context, completion: @escaping (Timeline<StepEntry>) -> ()) {
        let entry = StepEntry(date: Date(), steps: 1234)
        let timeline = Timeline(entries: [entry], policy: .atEnd)
        completion(timeline)
    }
}

struct StepWidgetEntryView: View {
    var entry: StepProvider.Entry
    var body: some View {
        Text("Steps: \(entry.steps)")
            .font(.headline)
    }
}

@main
struct StepWidget: Widget {
    let kind: String = "StepWidget"
    var body: some WidgetConfiguration {
        StaticConfiguration(kind: kind, provider: StepProvider()) { entry in
            StepWidgetEntryView(entry: entry)
        }
        .configurationDisplayName("Daily Steps")
        .description("Shows your daily step count.")
        .supportedFamilies([.accessoryRectangular, .accessoryInline])
    }
}

import SwiftUI

@Observable
class TimerModel {
    var seconds: Int = 0
    var isRunning: Bool = false
}

struct TimerView: View {
    @State private var model = TimerModel()
    var body: some View {
        VStack {
            Text("Seconds: \(model.seconds)")
            Button(model.isRunning ? "Stop" : "Start") {
                model.isRunning.toggle()
            }
        }
    }
}

